import scala.collection.mutable.ArrayBuffer

def solve(nums: Array[Long], queries: Array[Array[Long]]): Long = {
    val MOD = 1000000007L
    val n = nums.length
    val maxV = 100000

    def powMod(a: Long, exp: Long, mod: Long): Long = {
        var res = 1L
        var base = a % mod
        var e = exp
        while (e > 0) {
            if ((e & 1) == 1) res = (res * base) % mod
            base = (base * base) % mod
            e = e >> 1
        }
        res
    }

    val inv = new Array[Long](maxV + 1)
    for (i <- 1 to maxV) {
        inv(i) = powMod(i, MOD - 2, MOD)
    }

    val B = math.ceil(math.sqrt(n)).toInt
    val factor = Array.fill(n)(1L)

    val largeQueries = ArrayBuffer[Array[Long]]()
    val smallQueries = ArrayBuffer[Array[Long]]()

    for (q <- queries) {
        val k = q(2)
        if (k >= B) {
            largeQueries += q
        } else {
            smallQueries += q
        }
    }

    for (q <- largeQueries) {
        val l = q(0).toInt
        val r = q(1).toInt
        val k_val = q(2).toInt
        val v = q(3)
        var idx = l
        while (idx <= r) {
            factor(idx) = (factor(idx) * v) % MOD
            idx += k_val
        }
    }

    val groups = Array.fill(B)(ArrayBuffer[Array[Long]]())
    for (q <- smallQueries) {
        val k = q(2).toInt
        if (k < B && k > 0) {
            groups(k) += q
        }
    }

    for (k <- 1 until B) {
        val buf = groups(k)
        if (buf.nonEmpty) {
            for (r <- 0 until k) {
                val L = if (r < n) ( (n - 1 - r) / k + 1 ) else 0
                if (L > 0) {
                    val d = Array.fill(L + 2)(1L)
                    for (q <- buf) {
                        val l_val = q(0)
                        if (l_val % k == r) {
                            val r_val = q(1)
                            if (r_val >= r) {
                                val j_start = ((l_val - r) / k).toInt
                                val j_end = ((r_val - r) / k).toInt
                                if (j_start < L) {
                                    val v_val = q(3)
                                    d(j_start) = (d(j_start) * v_val) % MOD
                                    if (j_end + 1 < d.length) {
                                        d(j_end + 1) = (d(j_end + 1) * inv(v_val.toInt)) % MOD
                                    }
                                }
                            }
                        }
                    }
                    val prod = Array.ofDim[Long](L)
                    if (L > 0) {
                        var cur = d(0)
                        prod(0) = cur
                        for (j <- 1 until L) {
                            cur = (cur * d(j)) % MOD
                            prod(j) = cur
                        }
                    }
                    for (j <- 0 until L) {
                        val idx = r + j * k
                        if (idx < n) {
                            factor(idx) = (factor(idx) * prod(j)) % MOD
                        }
                    }
                }
            }
        }
    }

    var result = 0L
    for (i <- 0 until n) {
        val value = (nums(i) * factor(i)) % MOD
        result ^= value
    }
    result
}
