import scala.collection.mutable

def fastExpo(a: Long, exp: Long, mod: Long): Long = {
    var res = 1L
    var base = a % mod
    var e = exp
    while (e > 0) {
        if ((e & 1) == 1) {
            res = (res * base) % mod
        }
        base = (base * base) % mod
        e = e >> 1
    }
    res
}

def solve(nums: Array[Long], queries: Array[Array[Long]]): Long = {
    val mod = 1000000007L
    val n = nums.length
    val T = math.ceil(math.sqrt(n)).toInt
    val max_v = 100000
    val invTable = new Array[Long](max_v + 1)
    for (v0 <- 1 to max_v) {
        invTable(v0) = fastExpo(v0, mod - 2, mod)
    }

    val factor_large = Array.fill(n)(1L)
    val factor_small_total = Array.fill(n)(1L)

    val events_by_class = Array.ofDim[mutable.ListBuffer[(Int, Long)]](T)
    for (d <- 1 until T) {
        events_by_class(d) = Array.fill(d)(mutable.ListBuffer[(Int, Long)]())
    }

    queries.foreach { q =>
        val l = q(0).toInt
        val r = q(1).toInt
        val k = q(2).toInt
        val v = q(3).toInt

        if (k >= T) {
            var idx = l
            while (idx <= r) {
                factor_large(idx) = (factor_large(idx) * v) % mod
                idx += k
            }
        } else {
            val residue = l % k
            events_by_class(k)(residue) += ((l, v))
            if (r + 1 < n) {
                events_by_class(k)(residue) += ((r + 1, invTable(v)))
            }
        }
    }

    for (d <- 1 until T) {
        for (r <- 0 until d) {
            val events = events_by_class(d)(r).toList
            if (events.nonEmpty) {
                val sorted_events = events.sortBy(_._1)
                var current = 1L
                var event_index = 0
                var i0 = r
                while (i0 < n) {
                    while (event_index < sorted_events.length && sorted_events(event_index)._1 <= i0) {
                        current = (current * sorted_events(event_index)._2) % mod
                        event_index += 1
                    }
                    factor_small_total(i0) = (factor_small_total(i0) * current) % mod
                    i0 += d
                }
            }
        }
    }

    var result = 0L
    for (i <- 0 until n) {
        val base = nums(i) % mod
        val total = base * factor_large(i) % mod * factor_small_total(i) % mod
        result ^= total
    }

    result
}
```

### Explanation
- **Precomputation**: Modular inverses for values up to 100,000 are precomputed using fast exponentiation to handle division under modulo arithmetic efficiently.
- **Factor Arrays**: 
  - `factor_large` accumulates multipliers for large step queries by directly iterating over affected indices.
  - `factor_small_total` accumulates multipliers for small step queries using an event-based approach. Events (start and end indices) are processed in sorted order to compute the cumulative product of active multipliers for each residue class.
- **Event Processing**: For each residue class (modulus and residue), events are sorted by index. A sweep through indices in the residue class updates the cumulative product at each index.
- **Result Calculation**: The final value at each index is the product of the original value, large step factors, and small step factors. The bitwise XOR of these values gives the result.

This approach efficiently handles the constraints by leveraging arithmetic progression properties and modular arithmetic, ensuring optimal performance for large inputs.
